solution_code:
#include <iomanip>
#include <iostream>

class Percentage
{
    int m_pct{};
public:
    Percentage(int pct) : m_pct{ pct } {}

    explicit operator double() const
    {
        return m_pct / 100.0;
    }
};

int main()
{
    int p{};
    std::cin >> p;

    Percentage pct{ p };

    std::cout << std::fixed << std::setprecision(2)
              << static_cast<double>(pct) << '\n';

    return 0;
}

